-- EAGV nutrition module schema patch
-- Safe to rerun: creates missing tables, columns, constraints and indexes without dropping existing structures.
-- Compatibility notes:
--   * members(id) already uses UUID in this schema and is referenced as UUID.
--   * users(id) already uses INTEGER in this schema, so user-facing foreign keys keep INTEGER to avoid breaking compatibility.
--   * UUID primary keys in the new nutrition tables are intended to be generated by the API/ORM layer
--     (Prisma, EF Core, .NET APIs, FastAPI), avoiding a hard dependency on database UUID extensions.
--   * body_measurements and body_photos already exist and are only extended with missing fields/indexes.

BEGIN;

-- ---------------------------------------------------------------------------
-- ROOT TABLE: nutrition_profiles
-- ---------------------------------------------------------------------------

CREATE TABLE IF NOT EXISTS public.nutrition_profiles (
    id UUID PRIMARY KEY,
    member_id UUID NOT NULL,
    nutritionist_id INTEGER NOT NULL,
    basal_metabolic_rate NUMERIC(10, 2),
    daily_calorie_target NUMERIC(10, 2),
    water_intake_goal NUMERIC(10, 2),
    activity_level VARCHAR(80),
    sleep_hours NUMERIC(5, 2),
    stress_level VARCHAR(80),
    primary_goal VARCHAR(120),
    created_at TIMESTAMPTZ NOT NULL DEFAULT now(),
    updated_at TIMESTAMPTZ NOT NULL DEFAULT now()
);

ALTER TABLE public.nutrition_profiles ADD COLUMN IF NOT EXISTS member_id UUID;
ALTER TABLE public.nutrition_profiles ADD COLUMN IF NOT EXISTS nutritionist_id INTEGER;
ALTER TABLE public.nutrition_profiles ADD COLUMN IF NOT EXISTS basal_metabolic_rate NUMERIC(10, 2);
ALTER TABLE public.nutrition_profiles ADD COLUMN IF NOT EXISTS daily_calorie_target NUMERIC(10, 2);
ALTER TABLE public.nutrition_profiles ADD COLUMN IF NOT EXISTS water_intake_goal NUMERIC(10, 2);
ALTER TABLE public.nutrition_profiles ADD COLUMN IF NOT EXISTS activity_level VARCHAR(80);
ALTER TABLE public.nutrition_profiles ADD COLUMN IF NOT EXISTS sleep_hours NUMERIC(5, 2);
ALTER TABLE public.nutrition_profiles ADD COLUMN IF NOT EXISTS stress_level VARCHAR(80);
ALTER TABLE public.nutrition_profiles ADD COLUMN IF NOT EXISTS primary_goal VARCHAR(120);
ALTER TABLE public.nutrition_profiles ADD COLUMN IF NOT EXISTS created_at TIMESTAMPTZ DEFAULT now();
ALTER TABLE public.nutrition_profiles ADD COLUMN IF NOT EXISTS updated_at TIMESTAMPTZ DEFAULT now();

DO $$
BEGIN
    IF NOT EXISTS (
        SELECT 1
        FROM pg_constraint
        WHERE conname = 'fk_nutrition_profiles_member'
          AND conrelid = 'public.nutrition_profiles'::regclass
    ) THEN
        ALTER TABLE public.nutrition_profiles
            ADD CONSTRAINT fk_nutrition_profiles_member
            FOREIGN KEY (member_id) REFERENCES public.members(id) ON DELETE CASCADE;
    END IF;
END
$$;

DO $$
BEGIN
    IF NOT EXISTS (
        SELECT 1
        FROM pg_constraint
        WHERE conname = 'fk_nutrition_profiles_nutritionist'
          AND conrelid = 'public.nutrition_profiles'::regclass
    ) THEN
        ALTER TABLE public.nutrition_profiles
            ADD CONSTRAINT fk_nutrition_profiles_nutritionist
            FOREIGN KEY (nutritionist_id) REFERENCES public.users(id) ON DELETE RESTRICT;
    END IF;
END
$$;

CREATE INDEX IF NOT EXISTS ix_nutrition_profiles_member_id
    ON public.nutrition_profiles (member_id);

CREATE INDEX IF NOT EXISTS ix_nutrition_profiles_nutritionist_id
    ON public.nutrition_profiles (nutritionist_id);

COMMENT ON TABLE public.nutrition_profiles IS 'Root entity for nutrition workflows linked to members and nutritionists.';
COMMENT ON COLUMN public.nutrition_profiles.member_id IS 'FK to members(id).';
COMMENT ON COLUMN public.nutrition_profiles.nutritionist_id IS 'FK to users(id); users.id is INTEGER in the current schema.';

