ALTER TABLE public.nutrition_anamnesis ADD COLUMN IF NOT EXISTS nutrition_profile_id UUID;
ALTER TABLE public.nutrition_anamnesis ADD COLUMN IF NOT EXISTS meals_per_day INTEGER;
ALTER TABLE public.nutrition_anamnesis ADD COLUMN IF NOT EXISTS alcohol_consumption VARCHAR(80);
ALTER TABLE public.nutrition_anamnesis ADD COLUMN IF NOT EXISTS smoking BOOLEAN;
ALTER TABLE public.nutrition_anamnesis ADD COLUMN IF NOT EXISTS water_intake NUMERIC(10, 2);
ALTER TABLE public.nutrition_anamnesis ADD COLUMN IF NOT EXISTS digestive_issues TEXT;
ALTER TABLE public.nutrition_anamnesis ADD COLUMN IF NOT EXISTS food_cravings TEXT;
ALTER TABLE public.nutrition_anamnesis ADD COLUMN IF NOT EXISTS wake_up_time TIME;
ALTER TABLE public.nutrition_anamnesis ADD COLUMN IF NOT EXISTS sleep_time TIME;
ALTER TABLE public.nutrition_anamnesis ADD COLUMN IF NOT EXISTS work_routine TEXT;
ALTER TABLE public.nutrition_anamnesis ADD COLUMN IF NOT EXISTS previous_diets TEXT;
ALTER TABLE public.nutrition_anamnesis ADD COLUMN IF NOT EXISTS eating_disorders_history TEXT;
ALTER TABLE public.nutrition_anamnesis ADD COLUMN IF NOT EXISTS notes TEXT;
ALTER TABLE public.nutrition_anamnesis ADD COLUMN IF NOT EXISTS created_at TIMESTAMPTZ DEFAULT now();
ALTER TABLE public.nutrition_anamnesis ADD COLUMN IF NOT EXISTS updated_at TIMESTAMPTZ DEFAULT now();

DO $$
BEGIN
    IF NOT EXISTS (
        SELECT 1 FROM pg_constraint
        WHERE conname = 'fk_nutrition_anamnesis_profile'
          AND conrelid = 'public.nutrition_anamnesis'::regclass
