ALTER TABLE public.meal_plans ADD COLUMN IF NOT EXISTS title VARCHAR(160);
ALTER TABLE public.meal_plans ADD COLUMN IF NOT EXISTS objective TEXT;
ALTER TABLE public.meal_plans ADD COLUMN IF NOT EXISTS calories NUMERIC(10, 2);
ALTER TABLE public.meal_plans ADD COLUMN IF NOT EXISTS start_date DATE;
