-- ---------------------------------------------------------------------------
-- MEMBERSHIP-LEVEL EXISTING TABLE EXTENSIONS
-- ---------------------------------------------------------------------------

ALTER TABLE public.body_measurements ADD COLUMN IF NOT EXISTS visceral_fat NUMERIC(6, 2);
