    ON public.body_measurements (recorded_at DESC);

COMMENT ON COLUMN public.body_measurements.created_by IS 'FK kept on users(id) because the existing schema does not use employees(id).';
COMMENT ON COLUMN public.body_measurements.visceral_fat IS 'Optional visceral fat metric for nutrition and body-composition monitoring.';
COMMENT ON COLUMN public.body_measurements.bmi IS 'Optional BMI snapshot persisted for reporting interoperability.';

ALTER TABLE public.body_photos ADD COLUMN IF NOT EXISTS front_photo_url TEXT;
ALTER TABLE public.body_photos ADD COLUMN IF NOT EXISTS side_photo_url TEXT;
ALTER TABLE public.body_photos ADD COLUMN IF NOT EXISTS back_photo_url TEXT;
ALTER TABLE public.body_photos ADD COLUMN IF NOT EXISTS created_at TIMESTAMPTZ DEFAULT now();
ALTER TABLE public.body_photos ADD COLUMN IF NOT EXISTS updated_at TIMESTAMPTZ DEFAULT now();

-- Preserve compatibility with the legacy single-photo model by mapping existing rows into the new URL columns.
UPDATE public.body_photos
SET front_photo_url = COALESCE(front_photo_url, image_url)
WHERE type = 'front' AND front_photo_url IS NULL;

UPDATE public.body_photos
SET side_photo_url = COALESCE(side_photo_url, image_url)
WHERE type = 'side' AND side_photo_url IS NULL;

UPDATE public.body_photos
SET back_photo_url = COALESCE(back_photo_url, image_url)
WHERE type = 'back' AND back_photo_url IS NULL;

COMMENT ON COLUMN public.body_photos.front_photo_url IS 'Grouped-photo API field; legacy image_url/type columns remain supported.';
COMMENT ON COLUMN public.body_photos.side_photo_url IS 'Grouped-photo API field; legacy image_url/type columns remain supported.';
COMMENT ON COLUMN public.body_photos.back_photo_url IS 'Grouped-photo API field; legacy image_url/type columns remain supported.';

